INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (1, 1, 'CS 1800', 'Discrete Structures', 4, 'Introduces mathematical structures and methods that form the foundation of computer science, including sets, functions, logic, and counting techniques.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (2, 1, 'CS 2100', 'Program Design and Implementation 1', 4, 'Examines fundamentals of program design and implementation including data structures, object-oriented design patterns, and software engineering practices.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (3, 1, 'CS 2500', 'Fundamentals of Computer Science 1', 4, 'Introduces the design and analysis of algorithms, the management of information, and the principles of computation using a functional programming language.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (4, 1, 'CS 2510', 'Fundamentals of Computer Science 2', 4, 'Continues study of program design and data structures, emphasizing object-oriented design, mutation, and large-scale program construction.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (5, 1, 'CS 2800', 'Logic and Computation', 4, 'Introduces formal logic and its connections to computer science, covering propositional and first-order logic, logical inference, and mathematical induction.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (6, 1, 'CS 3000', 'Algorithms and Data', 4, 'Introduces principles and techniques for the design, analysis, and implementation of efficient algorithms and data representations.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (7, 1, 'CS 3100', 'Program Design and Implementation 2', 4, 'Builds on CS 2100 to examine program design at increasing scales of complexity, covering software design patterns and large-scale software projects.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (8, 1, 'CS 3200', 'Introduction to Databases', 4, 'Studies the design of a database for use in a relational database management system. Covers ER modeling, relational algebra, SQL, and advanced topics.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (9, 1, 'CS 3500', 'Object-Oriented Design', 4, 'Covers the principles and practices of designing large-scale object-oriented software systems using design patterns and SOLID principles.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (10, 1, 'CS 3650', 'Computer Systems', 4, 'Introduces basic design of computing systems, operating systems, and assembly language. Covers caches, virtual memory, system calls, and OS structures.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (11, 1, 'CS 3700', 'Networks and Distributed Systems', 4, 'Introduces fundamentals of computer networks, including architectures, protocols, and distributed program construction with emphasis on high-level protocols.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (12, 1, 'CS 3800', 'Theory of Computation', 4, 'Introduces the theory behind computers, covering automata theory, computability, and complexity including finite automata and Turing machines.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (13, 1, 'CS 4100', 'Artificial Intelligence', 4, 'Introduces fundamental problems, theories, and algorithms of AI, including heuristic search, knowledge representation, planning, and machine learning.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (14, 1, 'CS 4120', 'Natural Language Processing', 4, 'Introduces computational modeling of human language, covering computational grammar models, statistical language models, and NLP applications.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (15, 1, 'CS 4300', 'Computer Graphics', 4, 'Charts a path through major aspects of computer graphics: modeling, viewing, rendering, transformations, and interaction with hardware context.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (16, 1, 'CS 4400', 'Programming Languages', 4, 'Introduces a systematic approach to understanding programming language behavior, covering interpreters, scope, binding, type rules, and concurrency.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (17, 1, 'CS 4500', 'Software Development', 4, 'Covers large-scale software development practices, agile methods, code review, and collaborative development with substantial project work.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (18, 1, 'CS 4550', 'Web Development', 4, 'Covers design and implementation of web applications, including client-server architecture, REST APIs, databases, and modern front-end frameworks.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (19, 2, 'MATH 1341', 'Calculus 1 for Science and Engineering', 4, 'Covers limits, derivatives, and integrals of functions of one variable. Emphasizes conceptual understanding and problem-solving for STEM students.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (20, 2, 'MATH 1342', 'Calculus 2 for Science and Engineering', 4, 'Covers techniques of integration, series, polar coordinates, and introductory differential equations for science and engineering students.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (21, 2, 'MATH 2321', 'Calculus 3 for Science and Engineering', 4, 'Covers multivariable calculus including partial derivatives, multiple integrals, vector calculus, and the theorems of Green, Stokes, and Gauss.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (22, 2, 'MATH 2331', 'Linear Algebra', 4, 'Covers systems of linear equations, matrix algebra, determinants, vector spaces, eigenvalues, and linear transformations with applications.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (23, 2, 'MATH 3081', 'Probability and Statistics', 4, 'Introduces probability theory and statistical inference, covering discrete and continuous distributions, estimation, and hypothesis testing.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (24, 2, 'MATH 4545', 'Fourier Series and Partial Differential Equations', 4, 'Covers Fourier series, boundary value problems, partial differential equations, and their applications to heat, wave, and Laplace equations.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (25, 3, 'ECON 1115', 'Principles of Microeconomics', 4, 'Introduces microeconomic theory including supply and demand, consumer behavior, firm theory, market structures, and market failure.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (26, 3, 'ECON 1116', 'Principles of Macroeconomics', 4, 'Introduces macroeconomic theory including GDP, unemployment, inflation, monetary and fiscal policy, and the open economy.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (27, 3, 'ECON 2350', 'Probability and Statistics for Economists', 4, 'Covers statistical methods for economic analysis including probability, sampling distributions, regression analysis, and hypothesis testing.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (28, 4, 'DS 2500', 'Intermediate Programming with Data', 4, 'Covers intermediate programming using Python for data analysis, including data manipulation, visualization, and introductory machine learning.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (29, 4, 'DS 3000', 'Foundations of Data Science', 4, 'Introduces foundational concepts in data science including data cleaning, exploratory analysis, statistical modeling, and evaluation.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (30, 4, 'DS 3500', 'Advanced Programming with Data', 4, 'Covers advanced programming techniques for data-intensive applications, including parallel processing, APIs, and scalable data pipelines.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (31, 5, 'EECE 2160', 'Embedded Design Enabling Robotics', 4, 'Introduces embedded computing systems design, covering microcontrollers, C programming, digital I/O, and hardware-software integration.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (32, 5, 'EECE 2560', 'Fundamentals of Engineering Algorithms', 4, 'Covers algorithm design and analysis for engineering applications, including sorting, searching, and graph algorithms in C++.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (33, 6, 'PHYS 1151', 'Physics for Engineering 1', 4, 'Covers classical mechanics including kinematics, dynamics, energy, momentum, rotation, and oscillations for engineering students.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (34, 6, 'PHYS 1152', 'Physics for Engineering 2', 4, 'Covers electricity, magnetism, waves, optics, and introductory modern physics for engineering students.');
INSERT INTO Course (course_id, department_id, course_code, course_name, credits, description) VALUES (35, 8, 'ENGW 1111', 'First-Year Writing', 4, 'Develops academic writing skills through reading, analysis, and composition. Emphasizes research, argumentation, and revision.');
